import{_ as i,o as t,c as a,ae as l}from"./chunks/framework.BD9pLfSD.js";const d=JSON.parse('{"title":"Subject Manual","description":"","frontmatter":{},"headers":[],"relativePath":"en/3-subject-manual/index.md","filePath":"en/3-subject-manual/index.md"}'),r={name:"en/3-subject-manual/index.md"};function n(o,e,s,p,m,c){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="subject-manual" tabindex="-1">Subject Manual <a class="header-anchor" href="#subject-manual" aria-label="Permalink to &quot;Subject Manual&quot;">​</a></h1><p>Welcome to the CogniAND Psychology Experiment Platform! This manual will help you understand how to use the platform&#39;s features as a subject (experiment participant).</p><h2 id="what-is-a-subject" tabindex="-1">What is a Subject? <a class="header-anchor" href="#what-is-a-subject" aria-label="Permalink to &quot;What is a Subject?&quot;">​</a></h2><p>A subject is an experiment participant who can browse, apply for, and participate in various psychology experiments. On the CogniAND platform, subjects can:</p><ul><li>✅ Browse all public experiments</li><li>✅ Search and filter experiments of interest</li><li>✅ View experiment details and ratings</li><li>✅ Upload experiment data</li><li>✅ Rate experiments</li><li>✅ Manage personal profile</li><li>⚠️ Apply for experiments (placeholder feature)</li><li>⚠️ View participation history (placeholder feature)</li></ul><h2 id="quick-navigation" tabindex="-1">Quick Navigation <a class="header-anchor" href="#quick-navigation" aria-label="Permalink to &quot;Quick Navigation&quot;">​</a></h2><h3 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h3><ul><li><a href="./1-getting-started.html">Quick Start</a> - Understand subject features in 5 minutes</li><li><a href="./2-registration-login/">Registration &amp; Login</a> - Create a subject account</li></ul><h3 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h3><ul><li><a href="./3-browse-experiments/">Browse Experiments</a> - Find experiments of interest</li><li><a href="./4-participate-experiment/">Participate in Experiments</a> - Complete experiment participation process</li><li><a href="./5-personal-center.html">Personal Center</a> - Manage personal information</li><li><a href="./6-backstage.html">Backstage</a> - View participation history</li></ul><h3 id="important-information" tabindex="-1">Important Information <a class="header-anchor" href="#important-information" aria-label="Permalink to &quot;Important Information&quot;">​</a></h3><ul><li><a href="./7-permissions.html">Permissions</a> - Understand subject permissions and guidelines</li></ul><h2 id="feature-status" tabindex="-1">Feature Status <a class="header-anchor" href="#feature-status" aria-label="Permalink to &quot;Feature Status&quot;">​</a></h2><h3 id="✅-fully-implemented-features" tabindex="-1">✅ Fully Implemented Features <a class="header-anchor" href="#✅-fully-implemented-features" aria-label="Permalink to &quot;✅ Fully Implemented Features&quot;">​</a></h3><ol><li><p><strong>Registration &amp; Login</strong></p><ul><li>Standard registration (email + password)</li><li>Invitation registration (register through invitation link)</li><li>Email verification (receive verification code or link)</li><li>Password recovery (reset password via email)</li><li>Auto-login (remember login status)</li></ul></li><li><p><strong>Browse &amp; Search Experiments</strong></p><ul><li>Browse all public experiments</li><li>Search experiments by keywords</li><li>Filter by category, difficulty, duration</li><li>View experiment details (description, requirements, compensation, etc.)</li><li>View experiment ratings and reviews</li></ul></li><li><p><strong>Experiment Data Management</strong></p><ul><li>Upload experiment data (support file upload)</li><li>Rate participated experiments</li><li>View personal participation records</li></ul></li><li><p><strong>Personal Center</strong></p><ul><li>View and edit personal profile</li><li>Switch roles (if also an experimenter)</li><li>View message notifications</li><li>Submit feedback</li></ul></li></ol><h3 id="⚠️-partially-implemented-placeholder-features" tabindex="-1">⚠️ Partially Implemented/Placeholder Features <a class="header-anchor" href="#⚠️-partially-implemented-placeholder-features" aria-label="Permalink to &quot;⚠️ Partially Implemented/Placeholder Features&quot;">​</a></h3><ol><li><p><strong>Experiment Participation Process</strong> (placeholder API)</p><ul><li>Apply to participate in experiments</li><li>Start experiment tasks</li><li>Pause and resume experiments</li><li>View experiment progress</li></ul></li><li><p><strong>Experiment Favorites</strong> (frontend feature, backend placeholder)</p><ul><li>Favorite experiments of interest</li><li>View favorites list</li></ul></li><li><p><strong>Subject Backstage</strong> (placeholder API)</p><ul><li>View participation history</li><li>Manage experiment applications</li><li>View experiment results</li></ul></li></ol><h2 id="typical-workflow" tabindex="-1">Typical Workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical Workflow&quot;">​</a></h2><h3 id="complete-experiment-participation-process" tabindex="-1">Complete Experiment Participation Process <a class="header-anchor" href="#complete-experiment-participation-process" aria-label="Permalink to &quot;Complete Experiment Participation Process&quot;">​</a></h3><ol><li><p><strong>Browse Experiments</strong> (✅ Implemented)</p><ul><li>Log in and go to homepage</li><li>Browse recommended experiments or use search</li><li>Click on experiment of interest to view details</li></ul></li><li><p><strong>View Experiment Details</strong> (✅ Implemented)</p><ul><li>Read experiment description and requirements</li><li>Confirm experiment duration and compensation</li><li>View other subjects&#39; reviews</li></ul></li><li><p><strong>Apply to Participate</strong> (⚠️ Placeholder)</p><ul><li>Click &quot;Apply&quot; button</li><li>Fill in screening questionnaire (if any)</li><li>Wait for experimenter approval (if required)</li></ul></li><li><p><strong>Start Experiment</strong> (⚠️ Placeholder)</p><ul><li>Read and agree to informed consent</li><li>Follow experiment instructions to complete tasks</li><li>Can pause and resume during experiment</li></ul></li><li><p><strong>Submit Data</strong> (✅ Implemented)</p><ul><li>Upload data file after experiment completion</li><li>Support multiple file formats</li></ul></li><li><p><strong>Rate Experiment</strong> (✅ Implemented)</p><ul><li>Rate experiment (1-5 stars)</li><li>Help other subjects understand experiment quality</li></ul></li></ol><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><h3 id="what-subjects-can-do" tabindex="-1">What Subjects Can Do <a class="header-anchor" href="#what-subjects-can-do" aria-label="Permalink to &quot;What Subjects Can Do&quot;">​</a></h3><ul><li>✅ Browse all public experiments</li><li>✅ Search and filter experiments</li><li>✅ View experiment details</li><li>✅ Upload experiment data</li><li>✅ Rate experiments</li><li>✅ Manage personal profile</li><li>✅ Switch roles (if also an experimenter)</li><li>⚠️ Apply to participate (placeholder)</li><li>⚠️ View participation history (placeholder)</li></ul><h3 id="what-subjects-cannot-do" tabindex="-1">What Subjects Cannot Do <a class="header-anchor" href="#what-subjects-cannot-do" aria-label="Permalink to &quot;What Subjects Cannot Do&quot;">​</a></h3><ul><li>❌ View other subjects&#39; personal information</li><li>❌ Modify submitted experiment data</li><li>❌ Create or edit experiments</li><li>❌ View unpublished experiments</li><li>❌ Access experimenter or administrator functions</li></ul><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><h3 id="before-participating-in-experiments" tabindex="-1">Before Participating in Experiments <a class="header-anchor" href="#before-participating-in-experiments" aria-label="Permalink to &quot;Before Participating in Experiments&quot;">​</a></h3><ol><li><p><strong>Confirm Requirements</strong></p><ul><li>Carefully read experiment requirements</li><li>Confirm you meet participation conditions</li><li>Contact experimenter if you have questions</li></ul></li><li><p><strong>Understand Experiment Content</strong></p><ul><li>Read experiment description</li><li>Understand experiment duration</li><li>Understand experiment compensation</li></ul></li><li><p><strong>Prepare Experiment Environment</strong></p><ul><li>Ensure stable network connection</li><li>Prepare quiet environment</li><li>Ensure sufficient time</li></ul></li></ol><h3 id="during-experiment-participation" tabindex="-1">During Experiment Participation <a class="header-anchor" href="#during-experiment-participation" aria-label="Permalink to &quot;During Experiment Participation&quot;">​</a></h3><ol><li><p><strong>Complete Tasks Seriously</strong></p><ul><li>Follow experiment instructions</li><li>Answer questions truthfully</li><li>Do not cheat or fill randomly</li></ul></li><li><p><strong>Protect Personal Privacy</strong></p><ul><li>Do not disclose sensitive information during experiment</li><li>Pay attention to personal information protection</li></ul></li><li><p><strong>Provide Timely Feedback on Issues</strong></p><ul><li>Contact technical support for technical issues</li><li>Contact experimenter for experiment issues</li><li>Can exit anytime if uncomfortable</li></ul></li></ol><h3 id="after-experiment-participation" tabindex="-1">After Experiment Participation <a class="header-anchor" href="#after-experiment-participation" aria-label="Permalink to &quot;After Experiment Participation&quot;">​</a></h3><ol><li><p><strong>Submit Data</strong></p><ul><li>Confirm data completeness</li><li>Data cannot be modified after submission</li></ul></li><li><p><strong>Rate Experiment</strong></p><ul><li>Objectively rate experiment quality</li><li>Help other subjects and experimenters</li></ul></li><li><p><strong>View Results</strong></p><ul><li>Some experiments provide result feedback</li><li>Check message notifications</li></ul></li></ol><h2 id="experiment-types" tabindex="-1">Experiment Types <a class="header-anchor" href="#experiment-types" aria-label="Permalink to &quot;Experiment Types&quot;">​</a></h2><p>CogniAND platform supports various types of psychology experiments:</p><h3 id="cognitive-experiments" tabindex="-1">Cognitive Experiments <a class="header-anchor" href="#cognitive-experiments" aria-label="Permalink to &quot;Cognitive Experiments&quot;">​</a></h3><ul><li>Stroop Color-Word Interference Task</li><li>N-back Working Memory Task</li><li>Task Switching</li><li>Signal Detection Task</li><li>Eriksen Flanker Task</li><li>Anti-Saccade Task</li><li>Reversal Learning Task</li><li>And more...</li></ul><h3 id="emotion-experiments" tabindex="-1">Emotion Experiments <a class="header-anchor" href="#emotion-experiments" aria-label="Permalink to &quot;Emotion Experiments&quot;">​</a></h3><ul><li>Reading the Mind in the Eyes Test (RMET)</li><li>Empathy Tests</li><li>Empathy Choice</li><li>Empathy Accuracy</li><li>Pain Empathy</li><li>Ingroup Empathy</li><li>Awe Emotion</li><li>Gratitude Induction</li><li>Nostalgia Priming</li><li>And more...</li></ul><h3 id="social-cognition-experiments" tabindex="-1">Social Cognition Experiments <a class="header-anchor" href="#social-cognition-experiments" aria-label="Permalink to &quot;Social Cognition Experiments&quot;">​</a></h3><ul><li>Asch Conformity Experiment</li><li>Moral Judgment</li><li>Moral Inference</li><li>Social Exclusion</li><li>Social Comparison</li><li>Observational Learning</li><li>Cultural Attribution</li><li>Approach-Avoidance</li><li>Mouse Tracking</li><li>And more...</li></ul><h3 id="decision-game-theory-experiments" tabindex="-1">Decision &amp; Game Theory Experiments <a class="header-anchor" href="#decision-game-theory-experiments" aria-label="Permalink to &quot;Decision &amp; Game Theory Experiments&quot;">​</a></h3><ul><li>Dictator Game</li><li>Trust Game</li><li>Ultimatum Game</li><li>Prisoner&#39;s Dilemma</li><li>Public Goods Game</li><li>Third-Party Punishment</li><li>Intergroup Prisoner&#39;s Dilemma</li><li>Intergenerational Dilemma</li><li>Reputation Cooperation</li><li>And more...</li></ul><h3 id="self-related-experiments" tabindex="-1">Self-Related Experiments <a class="header-anchor" href="#self-related-experiments" aria-label="Permalink to &quot;Self-Related Experiments&quot;">​</a></h3><ul><li>Self-Reference Effect</li><li>Negative Self-Reference</li><li>Self-Perception Matching</li><li>Self-Orientation</li><li>Choice Blindness</li><li>Twenty Statements Test</li><li>And more...</li></ul><h3 id="perception-attention-experiments" tabindex="-1">Perception &amp; Attention Experiments <a class="header-anchor" href="#perception-attention-experiments" aria-label="Permalink to &quot;Perception &amp; Attention Experiments&quot;">​</a></h3><ul><li>Binocular Rivalry</li><li>Biological Motion Perception</li><li>Direct Gaze Perception</li><li>Dot Probe Task</li><li>Visual Search Task</li><li>Oddball Task</li><li>Psychomotor Vigilance Task</li><li>And more...</li></ul><p>For complete list, see: <a href="/en/4-platform-info/1-about.html">Platform Info - About</a></p><h2 id="need-help" tabindex="-1">Need Help? <a class="header-anchor" href="#need-help" aria-label="Permalink to &quot;Need Help?&quot;">​</a></h2><ul><li>Check <a href="/en/1-FAQ/">FAQ</a></li><li>Check <a href="/en/6-troubleshooting/">Troubleshooting</a></li><li>Contact <a href="/en/7-technical-support/1-contact.html">Technical Support</a></li></ul><hr><p><strong>Ready to start?</strong> Check <a href="./1-getting-started.html">Quick Start</a> to begin your first experiment!</p>',51)])])}const h=i(r,[["render",n]]);export{d as __pageData,h as default};
